package org.apache.commons.csv;

import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.*;

class CSVFormatTest {

    @Test
    void testGetTrim_DefaultFalse() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.getTrim());
    }

    @Test
    void testGetTrim_WithTrimTrue() {
        CSVFormat format = CSVFormat.DEFAULT.withTrim(true);
        assertTrue(format.getTrim());
    }

    @Test
    void testGetTrim_WithTrimFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withTrim(false);
        assertFalse(format.getTrim());
    }

    @Test
    void testGetTrim_ChainWithTrim() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreEmptyLines(true).withTrim(true);
        assertTrue(format.getTrim());
    }

    @Test
    void testGetTrim_ChainWithoutTrim() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreEmptyLines(true);
        assertFalse(format.getTrim());
    }
}
